class Solution {
    public String countOfAtoms(String formula) {
        int n = formula.length();
        Map<String, Integer> count = new TreeMap<>();
        int i = 0;
        while (i < n) {
            if (formula.charAt(i) == '(') {
                int j = i + 1, cnt = 0;
                while (cnt != 0 || formula.charAt(j) != ')') {
                    if (formula.charAt(j) == '(') cnt++;
                    else if (formula.charAt(j) == ')') cnt--;
                    j++;
                }
                String sub = formula.substring(i + 1, j - 1);
                int k = j;
                while (k < n && Character.isDigit(formula.charAt(k))) k++;
                int c = k > j ? Integer.parseInt(formula.substring(j, k)) : 1;
                Map<String, Integer> subCount = countOfAtoms(sub);
                for (String key : subCount.keySet()) {
                    count.put(key, count.getOrDefault(key, 0) + subCount.get(key) * c);
                }
                i = k;
            } else {
                int j = i + 1;
                while (j < n && Character.isLowerCase(formula.charAt(j))) j++;
                String atom = formula.substring(i, j);
                i = j;
                int c = 0;
                while (i < n && Character.isDigit(formula.charAt(i))) {
                    c = c * 10 + (formula.charAt(i++) - '0');
                }
                if (c == 0) c = 1;
                count.put(atom, count.getOrDefault(atom, 0) + c);
            }
        }
        StringBuilder sb = new StringBuilder();
        for (String key : count.keySet()) {
            sb.append(key);
            if (count.get(key) > 1) sb.append(count.get(key));
        }
        return sb.toString();
    }
}
